text:
{
  "formal_minutes": {
    "meeting_meta": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"]
    },
    "confirmed_decisions": [
      "대외 공개 릴리스 목표는 스모크 테스트 통과를 전제로 금요일 15:00 KST로 설정한다.",
      "packageName 불일치 발생 시 우선 패키지 설정(구성) 확인을 수행하고, 계약 자체가 잘못된 경우에만 스크립트 검토로 진행한다."
    ],
    "rejected_proposals": [
      "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경하자는 제안은 기각되었다."
    ],
    "internal_stretch_goals": [
      "수요일 릴리스 제안은 내부 스트레치 목표로만 남았고, 확정 일정이 아니다."
    ],
    "non_decisions": [
      "README 설치 절차는 가능하면 목요일 검토 제안이 있었으나 담당자가 지정되지 않았다.",
      "Hara의 tarball 경로 점검은 Minjun의 스모크 결과 공유 이후 수행하기로 했으나 정확한 마감 시각은 정해지지 않았다."
    ],
    "risks": [
      "tarball 경로 오류 시 릴리스가 지연될 수 있다.",
      "README 설치 절차가 최신이 아니면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 명시할 것인가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "미착수",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "미착수",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성 tarball 경로 점검",
      "due": "미정(선행조건: 스모크 결과 공유)",
      "status": "미착수",
      "source_certainty": "확정(마감 미확정)"
    },
    {
      "owner": "미지정",
      "task": "README 설치 절차 검토(가능하면 목요일)",
      "due": "목요일(권고, 확정 아님)",
      "status": "담당자 미지정",
      "source_certainty": "부분확정(필요성만 언급)"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 스모크 테스트 결과 통과/실패 여부 확인",
      "실패 시 금요일 12:00 KST 이전 Doyun의 트리아지 노트 작성 여부 확인",
      "스모크 결과 공유 직후 Hara의 tarball 경로 점검 결과 확인",
      "릴리스 전 README 설치 절차 최신성 및 실제 동작 검증",
      "최종 릴리스 승인 권한자 지정 여부 확인",
      "릴리스 노트에 수요일 내부 스트레치 목표를 포함할지 의사결정 확정"
    ],
    "do_not_invent": [
      "고객/외부 파트너 정보",
      "예산 수치 또는 예산 승인 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "미지정 담당자, 미합의 마감시각, 미합의 결정사항"
    ]
  },
  "non_invention_rules": [
    "원문 메모에 없는 고객명, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "확정된 결정과 제안/질문/스트레치 목표를 혼합하지 않는다.",
    "담당자 또는 마감이 명시되지 않은 항목은 '미지정/미정'으로 유지한다.",
    "조건부 결정(예: 스모크 통과 시 릴리스)을 무조건 결정으로 바꾸지 않는다.",
    "거절된 제안은 실행 항목으로 승격하지 않는다."
  ]
}
